/**
 * Tree-data preprocessing for DataGrid.
 *
 * Converts a flat row array into a display list with indentation metadata,
 * driven by `getTreeDataPath`. The DataGrid renders this list directly
 * instead of relying on TanStack Table's built-in tree features.
 *
 * @module data-grid-tree
 * @internal
 */
/** Metadata attached to each row in the flattened tree display list. */
type TreeRowMeta = {
    /** Zero-based depth level for indentation. */
    indent: number;
    /** Whether this row has child rows. */
    hasChildren: boolean;
    /** Whether this row is currently expanded (only meaningful when `hasChildren`). */
    isExpanded: boolean;
    /** Unique path key (segments joined with `/`). Used as the expand/collapse key. */
    pathKey: string;
};
/** A row in the flattened tree display list, pairing the original row with tree metadata. */
type TreeDisplayRow<TRow> = {
    row: TRow;
    meta: TreeRowMeta;
};
/**
 * Pre-process rows into a flat display list for tree rendering.
 *
 * @param rows          - Original flat row array
 * @param getTreeDataPath - Returns the hierarchy path for each row
 * @param expandedPaths - Set of currently expanded path keys
 * @returns Flattened display list with tree metadata
 */
declare function buildTreeDisplayList<TRow>(rows: TRow[], getTreeDataPath: (row: TRow) => string[], expandedPaths: ReadonlySet<string>): TreeDisplayRow<TRow>[];
/**
 * Toggle a path key in an expanded set, returning a new Set.
 */
declare function toggleTreePath(expandedPaths: Set<string>, pathKey: string): Set<string>;

export { type TreeDisplayRow, type TreeRowMeta, buildTreeDisplayList, toggleTreePath };
